solutionCode:
function describeEnrollmentSeeds(courseId, learnerPubkey) {
  const seeds = ["enrollment", courseId, learnerPubkey.toBase58()];

  return {
    seeds,
    count: seeds.length,
  };
}

testCode:
const { PublicKey } = require("@solana/web3.js");

const learner = new PublicKey("So11111111111111111111111111111111111111112");
const result = describeEnrollmentSeeds("anchor-101", learner);

assert(result.count === 3, "enrollment PDA uses 3 seeds");
assert(result.seeds[0] === "enrollment", "first seed should be 'enrollment'");
assert(result.seeds[1] === "anchor-101", "second seed should be the course ID");
assert(result.seeds[2] === learner.toBase58(), "third seed should be learner pubkey");
